{
  "phase": "plan",
  "decisions": [
    {
      "id": "d1",
      "decision": "Implement WebSocket protocol (RFC 6455 handshake + frame read/write) using only Python stdlib, no external library. The backend is stdlib-only (http.server) and adding a dependency like websockets/wsproto would be inconsistent.",
      "based_on": ["q1"],
      "alternatives_rejected": [
        "Add websockets library - async-first, conflicts with sync http.server architecture",
        "Add wsproto library - good protocol handling but adds a dependency to a zero-dependency backend",
        "Use SSE instead - frontend is already built for WebSocket, SSE would require rewriting the client"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d2",
      "decision": "Switch from HTTPServer to ThreadingHTTPServer so WebSocket connections can persist in their own threads while the server continues handling HTTP requests.",
      "based_on": ["q1"],
      "alternatives_rejected": [
        "Run WebSocket on a separate port - complicates deployment and frontend URL logic",
        "Use asyncio event loop - would require rewriting the entire server"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d3",
      "decision": "Broadcast MarketPriceMessage to WebSocket subscribers at the two points where marginals are mutated: (1) probability edit accepted (server.py ~line 2758) and (2) market resolution (server.py ~line 3446). Use the same MarketPriceMessage format the frontend expects.",
      "based_on": ["q2", "q3"],
      "alternatives_rejected": [
        "Broadcast on every event emission - too noisy, many events don't change marginals",
        "Periodic polling broadcast - defeats purpose of WebSocket push"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d4",
      "decision": "Keep React Query polling (5000ms) as-is. The frontend already implements dual-path (polling + WebSocket) with WebSocket updates feeding into the React Query cache via setQueryData. No frontend changes needed.",
      "based_on": ["q3", "q5"],
      "alternatives_rejected": [
        "Reduce polling interval when WebSocket connected - optimization for later, not needed now",
        "Remove polling entirely - reduces resilience"
      ],
      "reversibility": "easy"
    },
    {
      "id": "d5",
      "decision": "No new visual feedback beyond existing CSS transitions. ProbabilityBar already has 'transition: width 0.3s ease' which will animate smoothly when marginals update via WebSocket.",
      "based_on": ["q4"],
      "alternatives_rejected": [
        "Add flash/highlight animations - increases scope, can be added later"
      ],
      "reversibility": "easy"
    }
  ],
  "steps": [
    {
      "step": 1,
      "task": "Switch from HTTPServer to ThreadingHTTPServer in run_server() (server.py line 4427). Import ThreadingHTTPServer from http.server. This is a one-line change that enables concurrent connection handling.",
      "depends_on": [],
      "estimated_lines": 5,
      "risk": "low"
    },
    {
      "step": 2,
      "task": "Implement WebSocket protocol helpers as module-level functions: (a) ws_accept_key() to compute Sec-WebSocket-Accept from Sec-WebSocket-Key per RFC 6455, (b) ws_read_frame() to read and unmask a WebSocket frame from a socket, (c) ws_send_text() to send an unmasked text frame, (d) ws_send_close() to send a close frame. Place these near the top of server.py after imports.",
      "depends_on": [],
      "estimated_lines": 80,
      "risk": "medium"
    },
    {
      "step": 3,
      "task": "Add global WebSocket connection registry: WS_CONNECTIONS dict mapping market_id → set of socket objects, plus a _WS_LOCK threading.Lock for thread-safe access. Add helper functions ws_register(market_id, sock), ws_unregister(market_id, sock). Place near other global state (server.py ~line 173).",
      "depends_on": [],
      "estimated_lines": 25,
      "risk": "low"
    },
    {
      "step": 4,
      "task": "Add WebSocket upgrade detection in do_GET(): check for 'Upgrade: websocket' header and path matching /ws/markets/{marketId}/prices. If matched, perform the RFC 6455 handshake (send 101 Switching Protocols response), register the connection, enter a read loop (handling ping/pong/close frames), and unregister on disconnect. This runs in the handler thread (enabled by ThreadingHTTPServer).",
      "depends_on": [1, 2, 3],
      "estimated_lines": 60,
      "risk": "medium"
    },
    {
      "step": 5,
      "task": "Implement ws_broadcast(market_id) function: reads current market state from MARKETS[market_id], constructs a MarketPriceMessage JSON matching the frontend's expected format (marketId, status, marginals, seq, emittedAt, approxFlag, resolution, resolutionProbabilities), and sends it to all registered sockets for that market. Handles broken connections by unregistering them.",
      "depends_on": [3],
      "estimated_lines": 40,
      "risk": "low"
    },
    {
      "step": 6,
      "task": "Hook ws_broadcast() calls into the two marginals mutation points: (a) after probability edit acceptance where market['marginals'] is updated (~line 2758), and (b) after market resolution where status/marginals/resolution are set (~line 3446). Each hook is a single ws_broadcast(market_id) call.",
      "depends_on": [5],
      "estimated_lines": 10,
      "risk": "low"
    }
  ],
  "decomposition_assessment": {
    "total_steps": 6,
    "estimated_total_lines": 220,
    "high_risk_steps": 0,
    "parallelizable_groups": [["step1", "step2", "step3"], ["step4", "step5"], ["step6"]],
    "decision": "PROCEED_ALONE",
    "decision_reason": "Total estimated lines (220) is well under 500. No high-risk steps (2 medium, 4 low). All work is in a single file (server.py) with tightly coupled changes - the WebSocket protocol helpers, connection registry, upgrade handler, and broadcast function must all work together. Parallelization would be impractical since all changes are in one file. This is a focused backend task with a well-defined frontend contract."
  },
  "spawn_children": false,
  "children": []
}

{
  "phase": "question",
  "questions": [
    {
      "id": "q1",
      "question": "The backend already has SSE (Server-Sent Events) endpoints at /v1/markets/{id}/stream and /v1/accounts/{id}/risk/stream. Should we use these existing SSE endpoints (EventSource API) instead of adding WebSocket infrastructure, or does the task specifically require WebSocket protocol?",
      "category": "requirements",
      "why_it_matters": "SSE infrastructure is already built and tested on the backend. Adding WebSocket would require new backend code (ws library, upgrade handling, connection management) duplicating what SSE already provides. Using SSE means only frontend work is needed."
    },
    {
      "id": "q2",
      "question": "Which SSE event types should drive UI updates? The backend streams market_snapshot, terminal_event, and market_marginals for markets, plus risk_snapshot and risk_update for accounts. Should we subscribe to all of these or only market_marginals for price changes?",
      "category": "requirements",
      "why_it_matters": "Subscribing to all event types means more complex state management but richer real-time UX. Subscribing only to marginals is simpler but misses status changes and trade events."
    },
    {
      "id": "q3",
      "question": "Should the real-time connection fully replace the current React Query polling (refetchInterval: 5000ms), or should SSE updates supplement polling as an optimistic layer with polling as fallback?",
      "category": "design",
      "why_it_matters": "Replacing polling entirely is cleaner but requires robust reconnection logic. Keeping polling as fallback is more resilient but means maintaining two data paths."
    },
    {
      "id": "q4",
      "question": "Should price updates include visual feedback (flash/highlight animation) when a probability changes in real-time, or just silently update the displayed values?",
      "category": "requirements",
      "why_it_matters": "Visual feedback makes real-time updates obvious to users but adds UI complexity. Silent updates are simpler but users may not notice changes."
    },
    {
      "id": "q5",
      "question": "Which views need real-time updates? MarketDetail page only, or also MarketList (all markets overview), Analytics/PriceChart, and Portfolio views?",
      "category": "requirements",
      "why_it_matters": "MarketDetail is the most impactful and simplest scope. Expanding to MarketList means potentially many concurrent SSE connections. Analytics/charts need different update logic (appending data points vs replacing state)."
    }
  ],
  "assumptions": [
    {
      "id": "a1",
      "assumption": "We should use the existing SSE backend endpoints rather than adding WebSocket protocol support, since SSE is already implemented and sufficient for server-to-client price push.",
      "confidence": 0.85,
      "if_wrong": "Would need to add a WebSocket library to the Python backend (e.g. websockets), implement upgrade handling, duplicate the subscriber/publisher logic, and use the browser WebSocket API instead of EventSource on the frontend."
    },
    {
      "id": "a2",
      "assumption": "The frontend should use a custom React hook wrapping EventSource that integrates with the existing React Query cache, invalidating/updating cached market data when SSE events arrive.",
      "confidence": 0.9,
      "if_wrong": "Would need a separate state management layer (e.g. Zustand or Redux) alongside React Query, increasing complexity."
    },
    {
      "id": "a3",
      "assumption": "The initial scope is MarketDetail page only - subscribing to /v1/markets/{id}/stream when viewing a specific market and updating marginals + events in real-time.",
      "confidence": 0.7,
      "if_wrong": "If MarketList also needs real-time updates, we'd need a connection manager to handle multiple concurrent SSE streams or a single aggregate endpoint."
    },
    {
      "id": "a4",
      "assumption": "SSE reconnection can be handled by the browser's native EventSource auto-reconnect behavior, with the fromSeq query parameter for message replay on reconnect.",
      "confidence": 0.8,
      "if_wrong": "Would need custom reconnection logic with exponential backoff and manual EventSource recreation."
    },
    {
      "id": "a5",
      "assumption": "Polling can be reduced (e.g. 30s fallback) rather than eliminated entirely, keeping React Query as the source of truth with SSE updates feeding into the cache.",
      "confidence": 0.75,
      "if_wrong": "If polling must be fully removed, the SSE hook becomes the sole data source and needs more robust error handling and initial data loading."
    }
  ],
  "decomposition_assessment": {
    "complexity_score": 2,
    "complexity_reason": "Backend SSE infrastructure already exists. Work is primarily frontend: one custom hook for EventSource, integration with React Query cache, and updating 1-2 components. Estimated ~3-4 files changed, ~150-250 lines of new code.",
    "uncertainty_score": 2,
    "uncertainty_reason": "The SSE backend is already built and documented. EventSource API is well-understood. Main uncertainty is whether task literally requires WebSocket vs SSE, and exact scope of which views get real-time updates.",
    "independent_subproblems": [
      "Create useMarketStream hook wrapping EventSource with React Query cache integration",
      "Wire hook into MarketDetail page and update probability display components",
      "Add visual feedback (optional flash animation) for price changes"
    ],
    "decision": "PROCEED_ALONE",
    "decision_reason": "Complexity 2 and uncertainty 2 are both low. The backend work is done, so this is a focused frontend task touching 3-4 files. All subproblems are closely coupled (hook -> integration -> UI) and share state, making parallel execution impractical."
  },
  "spawn_children": false,
  "children": []
}

